"""
Pytest tests for HR Admin Bulk CSV Import feature.

Requirements tested:
1. HR-admin can bulk-import employees via CSV
2. Each row is validated individually
3. Only rows passing validation are committed
4. Errors are reported per row
5. The import action is idempotent under retry
"""

import io
import uuid
from http import HTTPStatus

import pytest


# ---------------------------------------------------------------------------
# Helpers / tiny domain model (replace with real imports in your project)
# ---------------------------------------------------------------------------

class ValidationError(Exception):
    pass


class Employee:
    def __init__(self, employee_id, first_name, last_name, email, department, salary):
        self.employee_id = employee_id
        self.first_name = first_name
        self.last_name = last_name
        self.email = email
        self.department = department
        self.salary = salary

    def __eq__(self, other):
        return isinstance(other, Employee) and self.employee_id == other.employee_id


class ImportRowResult:
    def __init__(self, *, row_number: int, success: bool, error: str | None = None):
        self.row_number = row_number
        self.success = success
        self.error = error

    def __repr__(self):
        return (
            f"ImportRowResult(row={self.row_number}, "
            f"success={self.success}, error={self.error!r})"
        )


class ImportReport:
    def __init__(self, results: list[ImportRowResult]):
        self.results = results

    @property
    def committed_count(self):
        return sum(1 for r in self.results if r.success)

    @property
    def error_count(self):
        return sum(1 for r in self.results if not r.success)

    @property
    def errors(self) -> list[ImportRowResult]:
        return [r for r in self.results if not r.success]

    @property
    def committed(self) -> list[ImportRowResult]:
        return [r for r in self.results if r.success]


# ---------------------------------------------------------------------------
# Fake in-memory repository (replace with your real DB/repo)
# ---------------------------------------------------------------------------

class FakeEmployeeRepository:
    """Deterministic, in-memory store that supports upsert semantics."""

    def __init__(self):
        self._store: dict[str, Employee] = {}

    def upsert(self, employee: Employee) -> bool:
        """Return True if this was a new insert, False if an update."""
        is_new = employee.employee_id not in self._store
        self._store[employee.employee_id] = employee
        return is_new

    def get(self, employee_id: str) -> Employee | None:
        return self._store.get(employee_id)

    def all(self) -> list[Employee]:
        return list(self._store.values())

    def count(self) -> int:
        return len(self._store)


