# The service under test (replace with your real service import)
# ---------------------------------------------------------------------------

import csv
import re


REQUIRED_HEADERS = {"employee_id", "first_name", "last_name", "email", "department", "salary"}
EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def _validate_row(row: dict, row_number: int) -> list[str]:
    """Return a list of human-readable validation error strings (empty = valid)."""
    errors: list[str] = []

    # --- presence checks ---
    for field in REQUIRED_HEADERS:
        if not row.get(field, "").strip():
            errors.append(f"Field '{field}' is required")

    if errors:          # no point in further checks if fields are missing
        return errors

    # --- email format ---
    if not EMAIL_RE.match(row["email"].strip()):
        errors.append(f"Invalid email address: {row['email']!r}")

    # --- salary must be a positive number ---
    try:
        salary = float(row["salary"].strip())
        if salary <= 0:
            errors.append(f"Salary must be positive, got {salary}")
    except ValueError:
        errors.append(f"Salary must be numeric, got {row['salary']!r}")

    # --- employee_id format: UUID or alphanumeric ≥ 3 chars ---
    emp_id = row["employee_id"].strip()
    if len(emp_id) < 3:
        errors.append(f"employee_id too short: {emp_id!r}")

    return errors


def import_employees_from_csv(
    csv_content: str | bytes,
    repository: FakeEmployeeRepository,
) -> ImportReport:
    """
    Parse *csv_content*, validate every row, commit only valid rows
    (upsert semantics for idempotency), and return an ImportReport.
    """
    if isinstance(csv_content, bytes):
        csv_content = csv_content.decode("utf-8")

    reader = csv.DictReader(io.StringIO(csv_content))

    # --- header validation ---
    if reader.fieldnames is None:
        return ImportReport([])

    missing_headers = REQUIRED_HEADERS - {h.strip() for h in reader.fieldnames}
    if missing_headers:
        raise ValueError(f"CSV is missing required headers: {missing_headers}")

    results: list[ImportRowResult] = []

    for i, raw_row in enumerate(reader, start=2):   # row 1 = header
        row = {k.strip(): v.strip() for k, v in raw_row.items()}
        validation_errors = _validate_row(row, i)

        if validation_errors:
            results.append(
                ImportRowResult(
                    row_number=i,
                    success=False,
                    error="; ".join(validation_errors),
                )
            )
        else:
            employee = Employee(
                employee_id=row["employee_id"],
                first_name=row["first_name"],
                last_name=row["last_name"],
                email=row["email"],
                department=row["department"],
                salary=float(row["salary"]),
            )
            repository.upsert(employee)
            results.append(ImportRowResult(row_number=i, success=True))

    return ImportReport(results)


