def repo():
    return FakeEmployeeRepository()


@pytest.fixture()
def valid_csv():
    return make_csv(
        "EMP001,Alice,Smith,alice@example.com,Engineering,90000",
        "EMP002,Bob,Jones,bob@example.com,Marketing,75000",
        "EMP003,Carol,White,carol@example.com,Finance,82000",
    )


