class TestHappyPath:

    def test_all_valid_rows_are_committed(self, repo, valid_csv):
        report = import_employees_from_csv(valid_csv, repo)
        assert report.committed_count == 3
        assert report.error_count == 0

    def test_committed_employees_exist_in_repository(self, repo, valid_csv):
        import_employees_from_csv(valid_csv, repo)
        assert repo.get("EMP001") is not None
        assert repo.get("EMP002") is not None
        assert repo.get("EMP003") is not None

    def test_committed_employee_data_is_correct(self, repo, valid_csv):
        import_employees_from_csv(valid_csv, repo)
        alice = repo.get("EMP001")
        assert alice.first_name == "Alice"
        assert alice.last_name == "Smith"
        assert alice.email == "alice@example.com"
