# ---------------------------------------------------------------------------
# Tests: partial validation (mixed valid/invalid)
# ---------------------------------------------------------------------------

class TestPartialValidation:

    def test_only_valid_rows_are_committed(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
