        assert repo.get("EMP011") is None
        assert repo.get("EMP012") is None

    def test_error_count_matches_invalid_rows(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        assert report.error_count == 2

    def test_errors_report_correct_row_numbers(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        error_rows = {e.row_number for e in report.errors}
        assert error_rows == {3, 4}     # rows 3 and 4 in the file (1-indexed, row 1 = header)

    def test_error_message_identifies_missing_field(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        row3_error = next(e for e in report.errors if e.row_number == 3)
        assert "first_name" in row3_error.error.lower()

    def test_error_message_identifies_invalid_email(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        row3_error = next(e for e in report.errors if e.row_number == 3)
