# ---------------------------------------------------------------------------
# Tests: per-row validation rules
# ---------------------------------------------------------------------------

class TestValidationRules:

    @pytest.mark.parametrize("missing_field,replacement", [
        ("employee_id", ",Alice,Smith,alice@x.com,Eng,50000"),
        ("first_name",  "EMP099,,Smith,alice@x.com,Eng,50000"),
        ("last_name",   "EMP099,Alice,,alice@x.com,Eng,50000"),
        ("email",       "EMP099,Alice,Smith,,Eng,50000"),
        ("department",  "EMP099,Alice,Smith,alice@x.com,,50000"),
        ("salary",      "EMP099,Alice,Smith,alice@x.com,Eng,"),
    ])
    def test_missing_required_field_fails_validation(self, repo, missing_field, replacement):
        csv_content = VALID_HEADERS + replacement
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 1
        assert missing_field in report.errors[0].error.lower()
        assert repo.count() == 0

    @pytest.mark.parametrize("bad_email", [
        "not-an-email",
        "missing@tld",
        "@nodomain.com",
        "spaces in@email.com",
    ])
    def test_invalid_email_format_fails_validation(self, repo, bad_email):
        csv_content = VALID_HEADERS + f"EMP099,Alice,Smith,{bad_email},Eng,50000"
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 1
        assert "email" in report.errors[0].error.lower()

    @pytest.mark.parametrize("bad_salary", ["abc", "-100", "0", "0.00"])
    def test_invalid_salary_fails_validation(self, repo, bad_salary):
        csv_content = VALID_HEADERS + f"EMP099,Alice,Smith,a@b.com,Eng,{bad_salary}"
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 1
        assert "salary" in report.errors[0].error.lower()

    @pytest.mark.parametrize("valid_salary", ["0.01", "1", "100000", "1234567.89"])
    def test_valid_salary_passes_validation(self, repo, valid_salary):
        csv_content = VALID_HEADERS + f"EMP099,Alice,Smith,a@b.com,Eng,{valid_salary}"
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 0
        assert repo.count() == 1

    def test_employee_id_too_short_fails_validation(self, repo):
        csv_content = VALID_HEADERS + "AB,Alice,Smith,a@b.com,Eng,50000"
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 1

    def test_row_with_multiple_errors_reports_all_errors(self, repo):
        csv_content = VALID_HEADERS + ",,,bad-email,Eng,abc"
        report = import_employees_from_csv(csv_content, repo)
        assert report.error_count == 1
        error_msg = report.errors[0].error
        # multiple distinct problems should be surfaced
        assert error_msg.count(";") >= 2


