class TestHeaderValidation:

    def test_missing_required_header_raises(self, repo):
        csv_content = "first_name,last_name,email,department,salary\n"
        csv_content += "Alice,Smith,alice@x.com,Eng,50000\n"
        with pytest.raises(ValueError, match="employee_id"):
            import_employees_from_csv(csv_content, repo)

    def test_extra_columns_are_ignored(self, repo):
        csv_content = (
            "employee_id,first_name,last_name,email,department,salary,phone\n"
            "EMP001,Alice,Smith,alice@x.com,Eng,50000,555-1234\n"
        )
        report = import_employees_from_csv(csv_content, repo)
        assert report.committed_count == 1

    def test_whitespace_in_headers_is_tolerated(self, repo):
        csv_content = (
            " employee_id , first_name , last_name , email , department , salary \n"
            "EMP001,Alice,Smith,alice@x.com,Eng,50000\n"
        )
        report = import_employees_from_csv(csv_content, repo)
        assert report.committed_count == 1

    def test_bytes_input_is_accepted(self, repo):
        csv_bytes = (VALID_HEADERS + "EMP001,Alice,Smith,alice@x.com,Eng,50000").encode("utf-8")
        report = import_employees_from_csv(csv_bytes, repo)
        assert report.committed_count == 1


# ---------------------------------------------------------------------------
# Tests: idempotency under retry
# ---------------------------------------------------------------------------

class TestIdempotency:

    def test_importing_same_csv_twice_does_not_duplicate_employees(self, repo, valid_csv):
        import_employees_from_csv(valid_csv, repo)
        import_employees_from_csv(valid_csv, repo)
        assert repo.count() == 3   # still only 3, not 6

    def test_second_import_returns_same_committed_count(self, repo, valid_csv):
        report1 = import_employees_from_csv(valid_csv, repo)
        report2 = import_employees_from_csv(valid_csv, repo)
        assert report1.committed_count == report2.committed_count

    def test_second_import_produces_no_new_errors_for_valid_csv(self, repo, valid_csv):
        import_employees_from_csv(valid_csv, repo)
        report2 = import_employees_from_csv(valid_csv, repo)
        assert report2.error_count == 0

    def test_employee_data_after_retry_matches_original(self, repo, valid_csv):
        import_employees_from_csv(valid_csv, repo)
        import_employees_from_csv(valid_csv, repo)
        alice = repo.get("EMP001")
        assert alice.email == "alice@example.com"
        assert alice.salary == 90000.0

    def test_updated_row_on_retry_overwrites_previous_data(self, repo):
        """If a corrected CSV is re-submitted the new data wins (upsert)."""
        first_run = VALID_HEADERS + "EMP001,Alice,Smith,alice@example.com,Engineering,90000"
        second_run = VALID_HEADERS + "EMP001,Alice,Smith,alice.new@example.com,Engineering,95000"

        import_employees_from_csv(first_run, repo)
        import_employees_from_csv(second_run, repo)

        alice = repo.get("EMP001")
        assert alice.email == "alice.new@example.com"
        assert alice.salary == 95000.0
        assert repo.count() == 1

    def test_partial_import_retry_commits_previously_failed_row(self, repo):
        """
        First import: one row valid, one invalid.
        After fixing the broken row, the second import should commit it too.
        """
        first_csv = make_csv(
            "EMP020,Heidi,Lang,heidi@example.com,HR,70000",        # valid
            "EMP021,Ivan,Lake,not-valid-email,Finance,65000",       # bad email
        )
        second_csv = make_csv(
            "EMP020,Heidi,Lang,heidi@example.com,HR,70000",         # same → idempotent
            "EMP021,Ivan,Lake,ivan@example.com,Finance,65000",       # fixed
        )

        report1 = import_employees_from_csv(first_csv, repo)
        assert report1.committed_count == 1
        assert report1.error_count == 1

        report2 = import_employees_from_csv(second_csv, repo)
        assert report2.committed_count == 2
        assert report2.error_count == 0
        assert repo.count() == 2

    def test_importing_identical_csv_n_times_is_stable(self, repo, valid_csv):
        for _ in range(5):
            report = import_employees_from_csv(valid_csv, repo)
            assert report.committed_count == 3
            assert report.error_count == 0

        assert repo.count() == 3

    def test_idempotency_with_mixed_csv(self, repo, mixed_csv):
        """Repeated imports of a mixed file keep the same committed / error split."""
        report1 = import_employees_from_csv(mixed_csv, repo)
        report2 = import_employees_from_csv(mixed_csv, repo)

        assert report1.committed_count == report2.committed_count
        assert report1.error_count == report2.error_count
        assert repo.count() == 2   # only the two valid rows, never more


# ---------------------------------------------------------------------------
# Tests: report structure & accessibility
# ---------------------------------------------------------------------------

class TestReportStructure:

    def test_report_exposes_per_row_results(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        assert len(report.results) == 4

    def test_each_result_has_row_number(self, repo, valid_csv):
        report = import_employees_from_csv(valid_csv, repo)
        row_numbers = [r.row_number for r in report.results]
        # data starts at row 2 (row 1 = header)
        assert row_numbers == [2, 3, 4]

    def test_error_result_contains_non_empty_message(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        for error_result in report.errors:
            assert error_result.error
            assert len(error_result.error.strip()) > 0

    def test_success_result_has_success_true(self, repo, valid_csv):
        report = import_employees_from_csv(valid_csv, repo)
        assert all(r.success for r in report.results)

    def test_error_result_has_success_false(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        for result in report.errors:
            assert result.success is False

    def test_committed_and_errors_are_mutually_exclusive(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        committed_rows = {r.row_number for r in report.committed}
        error_rows = {r.row_number for r in report.errors}
        assert committed_rows.isdisjoint(error_rows)

    def test_committed_plus_errors_equals_total_rows(self, repo, mixed_csv):
        report = import_employees_from_csv(mixed_csv, repo)
        assert report.committed_count + report.error_count == len(report.results)
